// config.js
import { AsyncStorage } from 'react-native';
import { randomBytes } from 'react-native-randombytes';
import CryptoJS from 'crypto-js';

const ENCRYPTION_KEY = randomBytes(32).toString('hex'); // Securely generate a key

export const encryptData = (data) => {
    const jsonData = JSON.stringify(data);
    const iv = randomBytes(16).toString('hex'); // Initialization vector
    const encrypted = CryptoJS.AES.encrypt(jsonData, CryptoJS.enc.Hex.parse(ENCRYPTION_KEY), {
        iv: CryptoJS.enc.Hex.parse(iv),
        mode: CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7
    }).toString();
    return { encryptedData: encrypted, iv };
};

export const decryptData = (encryptedData, iv) => {
    const decrypted = CryptoJS.AES.decrypt(encryptedData, CryptoJS.enc.Hex.parse(ENCRYPTION_KEY), {
        iv: CryptoJS.enc.Hex.parse(iv),
        mode: CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7
    });
    return JSON.parse(decrypted.toString(CryptoJS.enc.Utf8));
};

export const storeData = async (key, data) => {
    const { encryptedData, iv } = encryptData(data);
    await AsyncStorage.setItem(key, JSON.stringify({ encryptedData, iv }));
};

export const retrieveData = async (key) => {
    const result = await AsyncStorage.getItem(key);
    if (result) {
        const { encryptedData, iv } = JSON.parse(result);
        return decryptData(encryptedData, iv);
    }
    return null;
};